// Session Bootstrap Config — dynamically reads all infrastructure state
// Returns: auth patterns, webhook paths, table IDs, workflow IDs, phase status

const N8N_HOST = $vars.N8N_HOST;
const API_KEY = $vars.N8N_INTERNAL_API_KEY;

if (!N8N_HOST || !API_KEY) {
  throw new Error('Missing required vars: N8N_HOST=' + !!N8N_HOST + ', N8N_INTERNAL_API_KEY=' + !!API_KEY);
}

const API_BASE = N8N_HOST + '/api/v1';

// Helper: make authenticated n8n API call
async function n8nApi(path) {
  const resp = await this.helpers.httpRequest({
    method: 'GET',
    url: API_BASE + path,
    headers: { 'X-N8N-API-KEY': API_KEY },
    returnFullResponse: true,
  });
  return typeof resp.body === 'string' ? JSON.parse(resp.body) : resp.body;
}

// 1. Get ALL active workflows (paginated)
let allWorkflows = [];
let cursor = null;
for (let page = 0; page < 10; page++) {
  const params = cursor ? '?limit=100&cursor=' + cursor : '?limit=100&active=true';
  const result = await n8nApi.call(this, '/workflows' + params);
  const batch = result.data || [];
  allWorkflows = allWorkflows.concat(batch);
  if (!result.nextCursor || batch.length === 0) break;
  cursor = result.nextCursor;
}

// 2. Extract webhook paths from trigger nodes in each workflow
const webhookPaths = {};
const workflowIndex = {};

for (const wf of allWorkflows) {
  workflowIndex[wf.id] = {
    name: wf.name,
    active: wf.active,
    updatedAt: wf.updatedAt,
  };

  const nodes = wf.nodes || [];
  for (const node of nodes) {
    const nodeType = (node.type || '').toLowerCase();
    const params = node.parameters || {};

    // Only trigger webhooks — not respondToWebhook
    if (nodeType.includes('webhook') && !nodeType.includes('respond') && params.path) {
      const key = wf.name.replace(/[^a-zA-Z0-9]/g, '_').replace(/_+/g, '_').replace(/^_|_$/g, '');
      webhookPaths[key] = {
        workflow_id: wf.id,
        workflow_name: wf.name,
        path: '/webhook/' + params.path,
        method: params.httpMethod || 'GET',
        response_mode: params.responseMode || 'onReceived',
      };
    }
  }
}

// 3. Get all variables (paginated — n8n returns max 100 per page)
let allVars = [];
let varCursor = null;
for (let vPage = 0; vPage < 10; vPage++) {
  const vParams = varCursor ? '?limit=100&cursor=' + varCursor : '?limit=100';
  const varsResult = await n8nApi.call(this, '/variables' + vParams);
  const varBatch = varsResult.data || [];
  allVars = allVars.concat(varBatch);
  if (!varsResult.nextCursor || varBatch.length === 0) break;
  varCursor = varsResult.nextCursor;
}
const variables = {};
for (const v of allVars) {
  // Don't expose secret values, just confirm they exist
  const key = v.key || v.name;
  const val = v.value || '';
  const isSensitive = key.toLowerCase().includes('key') || 
                       key.toLowerCase().includes('secret') || 
                       key.toLowerCase().includes('token') ||
                       key.toLowerCase().includes('password');
  variables[key] = isSensitive ? '***exists***' : val;
}

// 4. Get DataTable IDs from variables
const tableIds = {
  registry: variables.REGISTRY_V2_API_TABLE_ID || 'NOT_SET',
  actions: variables.REGISTRY_V2_ACTION_TABLE_ID || 'NOT_SET',
  mcp_schemas: 'fSmVnP9qbbqQFAeI',
};

// 5. Verify DataTable access — try to read 1 row from each
const tableStatus = {};
for (const [name, tableId] of Object.entries(tableIds)) {
  if (tableId === 'NOT_SET') {
    tableStatus[name] = { status: 'error', message: 'Table ID variable not set' };
    continue;
  }
  try {
    const rows = await n8nApi.call(this, '/data-tables/' + tableId + '/rows?limit=1');
    tableStatus[name] = { 
      status: 'ok', 
      table_id: tableId,
      has_data: (rows.data || []).length > 0,
      has_more: !!rows.nextCursor,
    };
  } catch (e) {
    tableStatus[name] = { status: 'error', table_id: tableId, message: e.message };
  }
}

// 6. Critical workflow IDs (read from current active workflows)
const criticalWorkflows = {};
const criticalNames = {
  'orchestrate-v2': 'v2_gateway',
  'gateway-e2e-test': 'e2e_test',
  'system-audit': 'system_audit',
  'health-check-v2': 'health_monitor',
  'handler-google-suite': 'google_handler',
  'ai-gateway': 'mcp_gateway',
};

for (const [pathFragment, label] of Object.entries(criticalNames)) {
  for (const [key, info] of Object.entries(webhookPaths)) {
    if (info.path.includes(pathFragment)) {
      criticalWorkflows[label] = {
        workflow_id: info.workflow_id,
        webhook_path: info.path,
        method: info.method,
        active: true,
      };
      break;
    }
  }
}

// Also find non-webhook critical workflows
for (const wf of allWorkflows) {
  const name = wf.name || '';
  if (name.includes('Rate Limit') && !criticalWorkflows.rate_limiter) {
    criticalWorkflows.rate_limiter = { workflow_id: wf.id, active: wf.active };
  }
  if (name.includes('Backup') && name.includes('GitHub') && !name.includes('DataTable')) {
    criticalWorkflows.github_backup_wf = criticalWorkflows.github_backup_wf || { workflow_id: wf.id, active: wf.active };
  }
  if (name.includes('Backup') && name.includes('DataTable')) {
    criticalWorkflows.github_backup_dt = { workflow_id: wf.id, active: wf.active };
  }
  if (name.includes('MCP') && name.includes('Gateway')) {
    criticalWorkflows.mcp_gateway = criticalWorkflows.mcp_gateway || { workflow_id: wf.id, active: wf.active };
  }
}

// 7. Build the full config response
const config = {
  generated_at: new Date().toISOString(),
  n8n_host: N8N_HOST,

  auth_patterns: {
    n8n_rest_api: {
      header: 'X-N8N-API-KEY',
      note: 'NEVER use Authorization: Bearer for n8n REST API',
    },
    gateway_v2: {
      header: 'x-api-key',
      note: 'Use gateway master key or per-client key',
    },
    gateway_handlers: {
      header: 'x-internal-secret',
      note: 'Internal handler secret for workflow-to-workflow calls',
    },
    mcp_gateway: {
      header: 'Authorization: Bearer',
      note: 'MCP server trigger uses Bearer auth',
    },
  },

  shell_constraints: {
    default_shell: '/bin/sh (dash)',
    bash_available: '/usr/bin/bash',
    recommendation: 'Use python3 for all n8n API interaction — dash lacks bash features (source, declare -A, arrays)',
  },

  webhook_paths: webhookPaths,

  critical_workflows: criticalWorkflows,

  table_ids: tableIds,
  table_status: tableStatus,

  variables_present: Object.keys(variables),

  total_active_workflows: allWorkflows.length,
  total_webhook_endpoints: Object.keys(webhookPaths).length,

  e2e_notes: {
    trigger_path: criticalWorkflows.e2e_test?.webhook_path || 'NOT_FOUND',
    response_mode: 'onReceived (async — results sent via email, poll executions for programmatic access)',
    polling: 'GET /api/v1/executions?workflowId={id}&limit=1&status=success',
  },

  phase_status: {
    phase_a: 'COMPLETE — A1-A6 all verified',
    phase_b: 'COMPLETE — B1-B5 all verified (rate limiting, permissions, audit, schema validation)',
    phase_c: 'NOT STARTED — 36 E2E failures to debug',
    phase_d: 'NOT STARTED — API expansion (Kling, Suno, ElevenLabs)',
  },
};

return [{ json: config }];
